@namespace Lumeo
@implements IAsyncDisposable

@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium text-foreground mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<div id="@_wrapperId" class="@ContainerClass" @attributes="AdditionalAttributes">
    @* Trigger *@
    <button type="button" class="@TriggerClass" @onclick="ToggleOpen" id="@_triggerId" disabled="@Disabled"
            aria-describedby="@FormFieldDescribedBy"
            aria-required="@(Required ? "true" : "false")"
            aria-invalid="@(EffectiveInvalid ? "true" : "false")">
        @if (SelectedLabels.Count > 0)
        {
            <span class="truncate text-sm">@string.Join(" / ", SelectedLabels)</span>
        }
        else
        {
            <span class="text-sm text-muted-foreground">@(Placeholder ?? L["Cascader.Placeholder"])</span>
        }

        <span class="ms-auto flex items-center gap-1">
            @if (Clearable && Value is { Count: > 0 })
            {
                <button type="button" class="rounded-full hover:bg-foreground/20 p-0.5 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" aria-label="@L["Cascader.ClearSelection"]" @onclick="Clear" @onclick:stopPropagation="true">
                    <Blazicon Svg="Lucide.X" class="h-3.5 w-3.5 text-muted-foreground" />
                </button>
            }
            <Blazicon Svg="Lucide.ChevronDown" class="@($"h-4 w-4 text-muted-foreground transition-transform duration-200 {(_isOpen ? "rotate-180" : "")}")" />
        </span>
    </button>

    @* Dropdown panels *@
    @if (_isOpen)
    {
        <div id="@_contentId" class="@ContentClass" @onkeydown="HandleKeyDown" tabindex="-1">
            @if (ShowSearch)
            {
                <div class="px-2 py-1.5 border-b border-border/40">
                    <input type="text" placeholder="@L["Combobox.SearchPlaceholder"]"
                           class="flex h-7 w-full rounded-md border border-input bg-transparent px-2 py-1 text-xs placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                           value="@_searchText"
                           @oninput="OnSearchInput" />
                </div>
            }

            <div class="flex">
                @for (var levelIdx = 0; levelIdx <= _activePanels.Count; levelIdx++)
                {
                    var options = GetOptionsForLevel(levelIdx);
                    if (options.Count == 0) break;

                    var level = levelIdx;
                    <div class="@PanelClass" role="menu">
                        @for (var optIdx = 0; optIdx < options.Count; optIdx++)
                        {
                            var option = options[optIdx];
                            var idx = optIdx;
                            var isSelected = level < _selectedPath.Count && _selectedPath[level] == option.Value;
                            var hasChildren = option.Children is { Count: > 0 };
                            <button type="button"
                                    id="@OptionId(level, idx)"
                                    role="menuitem"
                                    aria-haspopup="@(hasChildren ? "menu" : null)"
                                    tabindex="@(level == _focusCol && idx == _focusIdx ? 0 : -1)"
                                    class="@GetOptionClass(isSelected)"
                                    @onclick="() => SelectOption(option, level)">
                                <span class="truncate">@option.Label</span>
                                @if (hasChildren)
                                {
                                    <Blazicon Svg="Lucide.ChevronRight" class="h-4 w-4 text-muted-foreground ms-auto shrink-0" />
                                }
                                else if (isSelected)
                                {
                                    <Blazicon Svg="Lucide.Check" class="h-4 w-4 text-primary ms-auto shrink-0" />
                                }
                            </button>
                        }
                    </div>
                }
            </div>
        </div>
    }
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive mt-1.5">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground mt-1.5">@HelperText</p>
    }
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    // aria-describedby on the trigger announces the FormField help/error to a screen
    // reader; the trigger keeps its own _triggerId (load-bearing for popover anchoring).
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    [Parameter] public List<string>? Value { get; set; }
    [Parameter] public EventCallback<List<string>?> ValueChanged { get; set; }
    [Parameter] public List<CascaderOption>? Options { get; set; }
    [Parameter] public string? Placeholder { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool Clearable { get; set; }
    [Parameter] public bool ShowSearch { get; set; }
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    private bool _isOpen;
    private bool _registered;
    private string _searchText = "";
    private readonly List<string> _selectedPath = [];
    private readonly List<CascaderOption> _activePanels = [];
    // Tracks the last Value we synced into the active-panel trail so that
    // OnParametersSet doesn't rebuild the trail on every parent re-render —
    // it should only respond when Value actually changes from outside.
    private List<string>? _lastSyncedValue;
    // Tracks the Options reference last synced. When async-loaded options
    // arrive after the Value parameter was already set, the value-based
    // guard alone would skip the rebuild and leave _selectedPath /
    // _activePanels empty — the trigger label would update via
    // SelectedLabels but opening the picker would land on the root with
    // no drill-down trail. Tracking Options separately lets us re-resolve
    // the trail once the options it refers to actually exist (Codex #81
    // review).
    private IReadOnlyList<CascaderOption>? _lastSyncedOptions;
    private readonly string _wrapperId = LumeoIds.New("cascader");
    private readonly string _triggerId = LumeoIds.New("cascader-trigger");
    private readonly string _contentId = LumeoIds.New("cascader-content");

    // Keyboard roving state: which column (panel) and which option index currently
    // holds focus. The matching option button carries tabindex=0 (all others -1), and
    // arrow keys move this position. _pendingFocusId is the DOM id to focus after the
    // next render (set during a keydown; applied in OnAfterRenderAsync once the target
    // — possibly a freshly-expanded child panel — is in the DOM).
    private int _focusCol;
    private int _focusIdx;
    private string? _pendingFocusId;

    private string OptionId(int col, int idx) => $"{_contentId}-opt-{col}-{idx}";
    private void QueueFocus() => _pendingFocusId = OptionId(_focusCol, _focusIdx);

    // Index of the parent option in column <paramref name="col"/> whose children are
    // currently expanded into col+1 (used so ArrowLeft lands back on that parent).
    private int ParentIndexAt(int col)
    {
        if (col < 0 || col >= _activePanels.Count) return 0;
        var i = GetOptionsForLevel(col).FindIndex(o => o.Value == _activePanels[col].Value);
        return i < 0 ? 0 : i;
    }

    private string ContainerClass => Cx.Merge("relative inline-block", Class);
    private string TriggerClass => $"flex items-center w-full h-9 px-3 rounded-md border {(EffectiveInvalid ? "border-destructive focus:ring-destructive/20" : "border-input")} bg-background text-sm hover:bg-accent/50 transition-colors disabled:cursor-not-allowed disabled:opacity-50 focus:outline-none focus:ring-[1.5px] {(EffectiveInvalid ? "focus:ring-destructive/20" : "focus:ring-ring")}";
    private const string ContentClass = "fixed z-50 overflow-hidden rounded-md border border-border/40 bg-popover text-popover-foreground shadow-lg animate-fade-in";
    private const string PanelClass = "min-w-[160px] max-h-64 overflow-y-auto border-e border-border/40 last:border-e-0 p-1";

    private List<string> SelectedLabels
    {
        get
        {
            if (Value is not { Count: > 0 } || Options is null) return [];
            var labels = new List<string>();
            var current = Options;
            foreach (var val in Value)
            {
                var opt = current.FirstOrDefault(o => o.Value == val);
                if (opt is null) break;
                labels.Add(opt.Label);
                current = opt.Children ?? [];
            }
            return labels;
        }
    }

    protected override void OnParametersSet()
    {
        // Skip rebuilds when neither Value NOR Options changed since the
        // last sync. Without this guard, any parent re-render (unrelated
        // sibling typing in a search box, parent route change, etc.) would
        // collapse the user's in-progress drill-down back to the
        // Value-mandated path even though nothing relevant changed.
        // Tracking Options separately matters because async-loaded
        // option trees often arrive AFTER Value has already been set —
        // without the Options check the rebuild gets skipped on that
        // arrival, and opening the picker still uses the empty panel
        // trail until Value changes again (Codex #81 review).
        var valueChanged = !ValueEquals(_lastSyncedValue, Value);
        var optionsChanged = !ReferenceEquals(_lastSyncedOptions, Options);
        if (!valueChanged && !optionsChanged) return;
        _lastSyncedValue = Value is null ? null : new List<string>(Value);
        _lastSyncedOptions = Options;

        // Rebuild the drill-down trail from the (possibly null) Value. A null /
        // empty Value — e.g. a programmatic reset by the parent — must clear the
        // selected-path highlight and the active panels; otherwise the old
        // highlighted path lingered because the rebuild was guarded behind a
        // "Count > 0" check that skipped the clear entirely on reset (#199).
        _selectedPath.Clear();
        _activePanels.Clear();

        if (Value is { Count: > 0 })
        {
            var current = Options ?? [];
            foreach (var val in Value)
            {
                var opt = current.FirstOrDefault(o => o.Value == val);
                if (opt is null) break;
                _selectedPath.Add(val);
                if (opt.Children is { Count: > 0 })
                {
                    _activePanels.Add(opt);
                    current = opt.Children;
                }
            }
        }
    }

    private static bool ValueEquals(List<string>? a, List<string>? b)
    {
        if (ReferenceEquals(a, b)) return true;
        if (a is null || b is null) return false;
        if (a.Count != b.Count) return false;
        for (int i = 0; i < a.Count; i++)
            if (!string.Equals(a[i], b[i], StringComparison.Ordinal)) return false;
        return true;
    }

    private List<CascaderOption> GetOptionsForLevel(int level)
    {
        if (level == 0)
        {
            var opts = Options ?? [];
            return string.IsNullOrWhiteSpace(_searchText)
                ? opts
                : SearchOptions(opts, _searchText);
        }

        if (level - 1 < _activePanels.Count)
        {
            return _activePanels[level - 1].Children ?? [];
        }

        return [];
    }

    private static List<CascaderOption> SearchOptions(List<CascaderOption> options, string search)
    {
        var result = new List<CascaderOption>();
        foreach (var opt in options)
        {
            if (opt.Label.Contains(search, StringComparison.OrdinalIgnoreCase))
            {
                result.Add(opt);
            }
            else if (opt.Children is { Count: > 0 })
            {
                var childMatches = SearchOptions(opt.Children, search);
                if (childMatches.Count > 0) result.Add(opt);
            }
        }
        return result;
    }

    private async Task SelectOption(CascaderOption option, int level)
    {
        // Keep keyboard roving in sync with the activated option so arrow keys resume
        // from here (e.g. after a mouse click or an Enter/Space activation).
        _focusCol = level;
        var clickedIdx = GetOptionsForLevel(level).FindIndex(o => o.Value == option.Value);
        _focusIdx = clickedIdx < 0 ? 0 : clickedIdx;

        // Trim path and panels to current level
        while (_selectedPath.Count > level) _selectedPath.RemoveAt(_selectedPath.Count - 1);
        while (_activePanels.Count > level) _activePanels.RemoveAt(_activePanels.Count - 1);

        _selectedPath.Add(option.Value);

        if (option.Children is { Count: > 0 })
        {
            _activePanels.Add(option);
        }
        else
        {
            // Leaf node — set value and close
            Value = [.._selectedPath];
            await ValueChanged.InvokeAsync(Value);
            await SetOpen(false);
        }
    }

    private async Task ToggleOpen() => await SetOpen(!_isOpen);

    private async Task SetOpen(bool value)
    {
        var wasOpen = _isOpen;
        _isOpen = value;
        if (!value) _searchText = "";
        // On open, seed roving focus on the first option of the first column.
        if (value) { _focusCol = 0; _focusIdx = 0; }

        // On close: return focus to the trigger button immediately (it is in the DOM).
        if (wasOpen && !value)
        {
            try { await Interop.FocusElement(_triggerId); } catch (JSDisconnectedException) { }
        }
        // On open: focus happens in OnAfterRenderAsync once the panel DOM is ready.
    }

    private async Task Clear()
    {
        Value = null;
        _selectedPath.Clear();
        _activePanels.Clear();
        await ValueChanged.InvokeAsync(null);
    }

    // Arrow-key roving across the cascader's columns (WAI-ARIA menu pattern):
    // Up/Down move within the focused column, Right drills into a parent's children
    // (focusing the first child), Left returns to the parent column, Home/End jump to
    // the column edges, and Enter/Space activate (select a leaf or expand a parent).
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await SetOpen(false);
                return;

            case "ArrowDown":
            {
                var count = GetOptionsForLevel(_focusCol).Count;
                if (count > 0) _focusIdx = Math.Min(_focusIdx + 1, count - 1);
                QueueFocus();
                break;
            }

            case "ArrowUp":
                _focusIdx = Math.Max(_focusIdx - 1, 0);
                QueueFocus();
                break;

            case "ArrowRight":
            {
                var opts = GetOptionsForLevel(_focusCol);
                if (_focusIdx >= 0 && _focusIdx < opts.Count && opts[_focusIdx].Children is { Count: > 0 })
                {
                    await SelectOption(opts[_focusIdx], _focusCol); // expands into the next column
                    _focusCol += 1;
                    _focusIdx = 0;
                    QueueFocus();
                }
                break;
            }

            case "ArrowLeft":
                if (_focusCol > 0)
                {
                    _focusCol -= 1;
                    _focusIdx = ParentIndexAt(_focusCol);
                    QueueFocus();
                }
                break;

            case "Home":
                _focusIdx = 0;
                QueueFocus();
                break;

            case "End":
            {
                var count = GetOptionsForLevel(_focusCol).Count;
                _focusIdx = count > 0 ? count - 1 : 0;
                QueueFocus();
                break;
            }

            case "Enter":
            case " ":
            {
                var opts = GetOptionsForLevel(_focusCol);
                if (_focusIdx >= 0 && _focusIdx < opts.Count)
                {
                    var opt = opts[_focusIdx];
                    await SelectOption(opt, _focusCol);
                    if (opt.Children is { Count: > 0 })
                    {
                        _focusCol += 1;
                        _focusIdx = 0;
                        QueueFocus();
                    }
                }
                break;
            }
        }
    }

    private void OnSearchInput(ChangeEventArgs e)
    {
        _searchText = e.Value?.ToString() ?? "";
    }

    private static string GetOptionClass(bool isSelected) =>
        $"flex w-full items-center gap-1 rounded-sm px-2 py-1.5 text-sm cursor-pointer transition-colors {(isSelected ? "bg-accent text-accent-foreground" : "hover:bg-accent/50")}";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_isOpen && !_registered)
        {
            await Interop.PositionFixed(_contentId, _triggerId, "start", false, "bottom");
            await Interop.RegisterClickOutside(_contentId, _triggerId, async () =>
            {
                await SetOpen(false);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;

            // Focus the first option in the first panel so keyboard users can
            // immediately navigate without an extra Tab press.
            _pendingFocusId = OptionId(0, 0);
        }
        else if (!_isOpen && _registered)
        {
            await Cleanup();
        }

        // Apply any queued roving focus once the target option (possibly in a
        // freshly-expanded child panel) has rendered into the DOM.
        if (_pendingFocusId is not null)
        {
            var id = _pendingFocusId;
            _pendingFocusId = null;
            try { await Interop.FocusElement(id); } catch (JSDisconnectedException) { }
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }

    public record CascaderOption
    {
        public string Label { get; init; } = "";
        public string Value { get; init; } = "";
        public List<CascaderOption>? Children { get; init; }
    }
}
